@dp.inline_query()
async def inline_query_handler(inline_query: types.InlineQuery):
    if inline_query.from_user.id not in ALLOWED_USER_IDS:
        try:
            await inline_query.answer([], cache_time=10, is_personal=True)
        except TelegramBadRequest:
            pass
        return

    query = inline_query.query.lower().strip()
    results = []

    for title, text in TEMPLATES.items():
        if query in title.lower():
            results.append(
                InlineQueryResultArticle(
                    id=title,
                    title=title,
                    description=text[:50] + "...",
                    input_message_content=InputTextMessageContent(
                        message_text=text
                    ),
                )
            )

            if len(results) >= 50:
                break

    if not results:
        results.append(
            InlineQueryResultArticle(
                id="none",
                title="❌ Шаблон не найден",
                description="Нет совпадений",
                input_message_content=InputTextMessageContent(
                    message_text="Нет такого шаблона. Попробуй другое ключевое слово!"
                )
            )
        )

    try:
        await inline_query.answer(
            results=results,
            cache_time=10,
            is_personal=True
        )
    except TelegramBadRequest as e:
        msg = str(e)
        if "query is too old" in msg or "query ID is invalid" in msg:
            return
        raise


async def main():
    while True:
        try:
            await dp.start_polling(bot)
        except TelegramNetworkError as e:
            print(f"[WARN] TelegramNetworkError: {e}. Ждём 5 секунд...")
            await asyncio.sleep(5)
        except Exception as e:
            print(f"[ERROR] Неожиданная ошибка: {e}. Ждём 5 секунд...")
            await asyncio.sleep(5)


if __name__ == "__main__":
    asyncio.run(main())
